## Overview

Create a new utility module `apps/server/src/lib/passcode-hash.ts` that provides `hashPasscode` and `verifyPasscode` functions using Node.js `crypto.scrypt` with timing-safe comparison.

## Step 1: Create `apps/server/src/lib/passcode-hash.ts`

```typescript
/**
 * Passcode hashing utilities using Node.js crypto.scrypt.
 *
 * Uses a 32-byte random salt and 64-byte derived key. Verification uses
 * timing-safe comparison to prevent timing attacks.
 *
 * @module lib/passcode-hash
 */
import { scrypt, randomBytes, timingSafeEqual } from 'node:crypto';
import { promisify } from 'node:util';

const scryptAsync = promisify(scrypt);
const KEY_LENGTH = 64;

/** Hash a plaintext passcode with a random salt. Returns hex-encoded hash and salt. */
export async function hashPasscode(passcode: string): Promise<{ hash: string; salt: string }> {
  const salt = randomBytes(32).toString('hex');
  const derived = (await scryptAsync(passcode, salt, KEY_LENGTH)) as Buffer;
  return { hash: derived.toString('hex'), salt };
}

/** Verify a plaintext passcode against a stored hash and salt using timing-safe comparison. */
export async function verifyPasscode(
  passcode: string,
  storedHash: string,
  storedSalt: string
): Promise<boolean> {
  const derived = (await scryptAsync(passcode, storedSalt, KEY_LENGTH)) as Buffer;
  const hashBuffer = Buffer.from(storedHash, 'hex');
  if (derived.length !== hashBuffer.length) return false;
  return timingSafeEqual(derived, hashBuffer);
}
```

## Step 2: Write tests in `apps/server/src/lib/__tests__/passcode-hash.test.ts`

```typescript
import { describe, it, expect } from 'vitest';
import { hashPasscode, verifyPasscode } from '../passcode-hash.js';

describe('passcode-hash', () => {
  describe('hashPasscode', () => {
    it('returns hash and salt as hex strings', async () => {
      const result = await hashPasscode('123456');
      expect(result.hash).toMatch(/^[0-9a-f]+$/);
      expect(result.salt).toMatch(/^[0-9a-f]+$/);
    });

    it('returns a 128-character hex hash (64 bytes)', async () => {
      const result = await hashPasscode('123456');
      expect(result.hash.length).toBe(128);
    });

    it('returns a 64-character hex salt (32 bytes)', async () => {
      const result = await hashPasscode('123456');
      expect(result.salt.length).toBe(64);
    });

    it('produces different salts for each call', async () => {
      const a = await hashPasscode('123456');
      const b = await hashPasscode('123456');
      expect(a.salt).not.toBe(b.salt);
    });

    it('produces different hashes for the same input due to unique salts', async () => {
      const a = await hashPasscode('123456');
      const b = await hashPasscode('123456');
      expect(a.hash).not.toBe(b.hash);
    });
  });

  describe('verifyPasscode', () => {
    it('returns true for correct passcode', async () => {
      const { hash, salt } = await hashPasscode('654321');
      const valid = await verifyPasscode('654321', hash, salt);
      expect(valid).toBe(true);
    });

    it('returns false for incorrect passcode', async () => {
      const { hash, salt } = await hashPasscode('654321');
      const valid = await verifyPasscode('000000', hash, salt);
      expect(valid).toBe(false);
    });

    it('returns false when hash length does not match (no throw)', async () => {
      const { salt } = await hashPasscode('654321');
      const valid = await verifyPasscode('654321', 'short', salt);
      expect(valid).toBe(false);
    });

    it('different salts produce different hashes for the same passcode', async () => {
      const a = await hashPasscode('111111');
      const b = await hashPasscode('111111');
      const crossValid = await verifyPasscode('111111', a.hash, b.salt);
      expect(crossValid).toBe(false);
    });
  });
});
```

## Acceptance Criteria

1. `hashPasscode('123456')` returns `{ hash: string, salt: string }` where both are hex-encoded
2. Hash is 128 hex chars (64 bytes), salt is 64 hex chars (32 bytes)
3. `verifyPasscode` returns `true` for the correct passcode and `false` for incorrect ones
4. `verifyPasscode` returns `false` (not throws) when stored hash length does not match derived key length
5. Each call to `hashPasscode` produces a unique salt (and therefore unique hash)
6. Using the wrong salt for verification returns `false`
7. All 8 test scenarios pass: `pnpm vitest run apps/server/src/lib/__tests__/passcode-hash.test.ts`

## Overview

Install the `cookie-session` npm package as a server dependency, then configure it as Express middleware in `apps/server/src/app.ts`. Also set `trust proxy` for correct IP detection behind ngrok. The session secret is auto-generated on first run and persisted to the config file.

## Step 1: Install cookie-session

Run:
```bash
pnpm --filter=@dorkos/server add cookie-session
pnpm --filter=@dorkos/server add -D @types/cookie-session
```

## Step 2: Modify `apps/server/src/app.ts`

Add new imports at the top of the file:

```typescript
import crypto from 'node:crypto';
import cookieSession from 'cookie-session';
import { PASSCODE_SESSION_MAX_AGE_MS } from '@dorkos/shared/constants';
import { configManager } from './services/core/config-manager.js';
```

Inside the `createApp()` function, after the existing `app.use(requestLogger);` line and before the API route mounts, add:

```typescript
// Trust the immediate upstream proxy (ngrok) for correct IP and protocol detection
app.set('trust proxy', 1);

// Auto-generate session secret on first run, persist to config
let sessionSecret = configManager.get('sessionSecret');
if (!sessionSecret) {
  sessionSecret = crypto.randomBytes(32).toString('hex');
  configManager.set('sessionSecret', sessionSecret);
}

app.use(
  cookieSession({
    name: 'dorkos_session',
    keys: [sessionSecret],
    maxAge: PASSCODE_SESSION_MAX_AGE_MS,
    httpOnly: true,
    secure: true,
    sameSite: 'strict',
  })
);
```

The middleware order in `createApp()` must be:
1. `cors`
2. `express.json()`
3. `requestLogger`
4. `trust proxy` setting
5. `cookieSession`
6. Route handlers

## Step 3: Add TypeScript type augmentation for session

Create a type declaration file at `apps/server/src/types/cookie-session.d.ts` (or add to an existing declarations file):

```typescript
