  }
}
```

Alternatively, if the project uses `express-serve-static-core` augmentation, augment `req.session` there. The key point is that `req.session?.tunnelAuthenticated` must typecheck without errors.

## Acceptance Criteria

1. `cookie-session` and `@types/cookie-session` are in server `package.json` dependencies/devDependencies
2. `app.set('trust proxy', 1)` is called before cookie-session middleware
3. Session secret is auto-generated via `crypto.randomBytes(32).toString('hex')` and stored via `configManager.set('sessionSecret', ...)`
4. On subsequent server starts, the persisted secret is reused (not regenerated)
5. Cookie config: `name: 'dorkos_session'`, `httpOnly: true`, `secure: true`, `sameSite: 'strict'`, `maxAge: PASSCODE_SESSION_MAX_AGE_MS` (24 hours)
6. `req.session.tunnelAuthenticated` typechecks as `boolean | undefined`
7. `pnpm typecheck` passes
8. `pnpm build` succeeds with the new dependency

## Overview

Create a new Express middleware at `apps/server/src/middleware/tunnel-auth.ts` that intercepts tunnel (non-localhost) requests and returns 401 if the user has not authenticated via passcode. Local requests always pass through. Certain routes are exempt (passcode entry endpoints, health check, static assets).

## Step 1: Create `apps/server/src/middleware/tunnel-auth.ts`

```typescript
/**
 * Tunnel passcode authentication middleware.
 *
 * Gates non-localhost requests behind passcode verification when enabled.
 * Local access (localhost / 127.0.0.1) is always unrestricted.
 * Exempt routes allow the passcode entry page and health checks to load.
 *
 * @module middleware/tunnel-auth
 */
import type { Request, Response, NextFunction } from 'express';
import { configManager } from '../services/core/config-manager.js';

const EXEMPT_PREFIXES = [
  '/api/tunnel/verify-passcode',
  '/api/tunnel/session',
  '/api/health',
  '/assets/',
  '/favicon.ico',
];

/** Check if a request path is exempt from passcode authentication. */
function isExempt(path: string): boolean {
  return EXEMPT_PREFIXES.some((prefix) => path.startsWith(prefix));
}

/** Check if a request originates from a tunnel (non-localhost) hostname. */
function isTunnelRequest(req: Request): boolean {
  const hostname = req.hostname;
  return hostname !== 'localhost' && hostname !== '127.0.0.1';
}

/** Express middleware that enforces passcode authentication for tunnel requests. */
export function tunnelPasscodeAuth(req: Request, res: Response, next: NextFunction): void {
  // Local access is always unrestricted
  if (!isTunnelRequest(req)) {
    next();
    return;
  }

  // Check if passcode is configured and enabled
  const tunnelConfig = configManager.get('tunnel');
  if (!tunnelConfig?.passcodeEnabled || !tunnelConfig?.passcodeHash) {
    next();
    return;
  }

  // Exempt routes (passcode entry page, health checks, static assets)
  if (isExempt(req.path)) {
    next();
    return;
  }

  // Check session cookie (set by cookie-session middleware)
  if (req.session?.tunnelAuthenticated) {
    next();
    return;
  }

  // Not authenticated â€” return 401
  res.status(401).json({ error: 'Passcode required' });
}
```

## Step 2: Register middleware in `apps/server/src/app.ts`

Add the import at the top:

```typescript
import { tunnelPasscodeAuth } from './middleware/tunnel-auth.js';
```

In `createApp()`, add the middleware call after `cookieSession` and before route handlers:

```typescript
app.use(tunnelPasscodeAuth);
```

Final middleware order:
1. `cors`
2. `express.json()`
3. `requestLogger`
4. `trust proxy`
5. `cookieSession`
6. `tunnelPasscodeAuth`
7. Route handlers

## Step 3: Write tests in `apps/server/src/middleware/__tests__/tunnel-auth.test.ts`

```typescript
import { describe, it, expect, vi, beforeEach } from 'vitest';
import type { Request, Response, NextFunction } from 'express';
import { tunnelPasscodeAuth } from '../tunnel-auth.js';
import { configManager } from '../../services/core/config-manager.js';

vi.mock('../../services/core/config-manager.js', () => ({
  configManager: { get: vi.fn() },
}));

function createMockReq(overrides: Partial<Request> = {}): Request {
  return {
    hostname: 'localhost',
    path: '/api/sessions',
    session: {},
    ...overrides,
  } as unknown as Request;
}

function createMockRes(): Response {
  const res = {
    status: vi.fn().mockReturnThis(),
    json: vi.fn().mockReturnThis(),
  };
  return res as unknown as Response;
}

describe('tunnelPasscodeAuth', () => {
  let next: NextFunction;

  beforeEach(() => {
    vi.clearAllMocks();
    next = vi.fn();
  });

  it('passes through for localhost requests', () => {
    const req = createMockReq({ hostname: 'localhost' });
    const res = createMockRes();
    tunnelPasscodeAuth(req, res, next);
    expect(next).toHaveBeenCalled();
  });

  it('passes through for 127.0.0.1 requests', () => {
    const req = createMockReq({ hostname: '127.0.0.1' });
    const res = createMockRes();
    tunnelPasscodeAuth(req, res, next);
    expect(next).toHaveBeenCalled();
  });

  it('passes through when passcode is not enabled', () => {
    vi.mocked(configManager.get).mockReturnValue({
      passcodeEnabled: false,
      passcodeHash: null,
    });
    const req = createMockReq({ hostname: 'abc123.ngrok-free.app' });
    const res = createMockRes();
    tunnelPasscodeAuth(req, res, next);
    expect(next).toHaveBeenCalled();
  });

  it('passes through when passcode hash is null', () => {
    vi.mocked(configManager.get).mockReturnValue({
      passcodeEnabled: true,
      passcodeHash: null,
    });
    const req = createMockReq({ hostname: 'abc123.ngrok-free.app' });
    const res = createMockRes();
    tunnelPasscodeAuth(req, res, next);
    expect(next).toHaveBeenCalled();
  });

  it('passes through for exempt route /api/tunnel/verify-passcode', () => {
    vi.mocked(configManager.get).mockReturnValue({
      passcodeEnabled: true,
      passcodeHash: 'somehash',
    });
    const req = createMockReq({
      hostname: 'abc123.ngrok-free.app',
      path: '/api/tunnel/verify-passcode',
    });
    const res = createMockRes();
    tunnelPasscodeAuth(req, res, next);
    expect(next).toHaveBeenCalled();
  });

  it('passes through for exempt route /api/tunnel/session', () => {
    vi.mocked(configManager.get).mockReturnValue({
      passcodeEnabled: true,
      passcodeHash: 'somehash',
    });
    const req = createMockReq({
      hostname: 'abc123.ngrok-free.app',
      path: '/api/tunnel/session',
    });
    const res = createMockRes();
    tunnelPasscodeAuth(req, res, next);
    expect(next).toHaveBeenCalled();
  });

  it('passes through for exempt route /api/health', () => {
    vi.mocked(configManager.get).mockReturnValue({
      passcodeEnabled: true,
      passcodeHash: 'somehash',
    });
    const req = createMockReq({
      hostname: 'abc123.ngrok-free.app',
      path: '/api/health',
    });
    const res = createMockRes();
    tunnelPasscodeAuth(req, res, next);
    expect(next).toHaveBeenCalled();
  });

  it('passes through for exempt route /assets/style.css', () => {
    vi.mocked(configManager.get).mockReturnValue({
      passcodeEnabled: true,
      passcodeHash: 'somehash',
    });
    const req = createMockReq({
      hostname: 'abc123.ngrok-free.app',
      path: '/assets/style.css',
    });
    const res = createMockRes();
    tunnelPasscodeAuth(req, res, next);
    expect(next).toHaveBeenCalled();
  });

  it('returns 401 for tunnel requests without session cookie', () => {
    vi.mocked(configManager.get).mockReturnValue({
      passcodeEnabled: true,
      passcodeHash: 'somehash',
    });
    const req = createMockReq({
      hostname: 'abc123.ngrok-free.app',
      path: '/api/sessions',
      session: {},
    });
    const res = createMockRes();
    tunnelPasscodeAuth(req, res, next);
    expect(next).not.toHaveBeenCalled();
    expect(res.status).toHaveBeenCalledWith(401);
    expect(res.json).toHaveBeenCalledWith({ error: 'Passcode required' });
  });

  it('passes through for tunnel requests with valid session cookie', () => {
    vi.mocked(configManager.get).mockReturnValue({
      passcodeEnabled: true,
      passcodeHash: 'somehash',
    });
    const req = createMockReq({
      hostname: 'abc123.ngrok-free.app',
      path: '/api/sessions',
      session: { tunnelAuthenticated: true },
    });
    const res = createMockRes();
    tunnelPasscodeAuth(req, res, next);
    expect(next).toHaveBeenCalled();
  });

  it('returns 401 for tunnel requests with expired/invalid session cookie', () => {
    vi.mocked(configManager.get).mockReturnValue({
      passcodeEnabled: true,
      passcodeHash: 'somehash',
    });
    const req = createMockReq({
      hostname: 'abc123.ngrok-free.app',
      path: '/api/sessions',
      session: { tunnelAuthenticated: false },
    });
    const res = createMockRes();
    tunnelPasscodeAuth(req, res, next);
    expect(next).not.toHaveBeenCalled();
    expect(res.status).toHaveBeenCalledWith(401);
  });
});
```

## Acceptance Criteria

1. Middleware passes through for `localhost` and `127.0.0.1` hostname requests regardless of passcode state
2. Middleware passes through when `passcodeEnabled` is `false` or `passcodeHash` is `null`
3. Middleware passes through for all exempt paths: `/api/tunnel/verify-passcode`, `/api/tunnel/session`, `/api/health`, `/assets/*`, `/favicon.ico`
4. Middleware passes through when `req.session.tunnelAuthenticated` is `true`
5. Middleware returns `401 { error: 'Passcode required' }` for unauthenticated tunnel requests
6. Middleware is registered in `app.ts` after `cookieSession` and before route handlers
7. All 11 test scenarios pass: `pnpm vitest run apps/server/src/middleware/__tests__/tunnel-auth.test.ts`

## Overview

Add three new endpoints to the existing tunnel router (`apps/server/src/routes/tunnel.ts`): `POST /api/tunnel/verify-passcode`, `GET /api/tunnel/session`, and `POST /api/tunnel/set-passcode`. Also add a rate limiter for the verify endpoint.

## Step 1: Add imports to `apps/server/src/routes/tunnel.ts`

Add these imports at the top of the file:

```typescript
import rateLimit from 'express-rate-limit';
import {
  PASSCODE_RATE_LIMIT_WINDOW_MS,
  PASSCODE_RATE_LIMIT_MAX,
} from '@dorkos/shared/constants';
import { PasscodeVerifyRequestSchema } from '@dorkos/shared/schemas';
import { hashPasscode, verifyPasscode } from '../lib/passcode-hash.js';
```

Note: `express-rate-limit` is already installed in the server package.

## Step 2: Add rate limiter definition

After the existing `resolveTunnelPort()` function, add:

```typescript
const passcodeRateLimiter = rateLimit({
  windowMs: PASSCODE_RATE_LIMIT_WINDOW_MS,
  max: PASSCODE_RATE_LIMIT_MAX,
  standardHeaders: true,
  legacyHeaders: false,
  message: { ok: false, error: 'Too many attempts. Try again later.', retryAfter: 900 },
  keyGenerator: (req) => req.ip ?? 'unknown',
});
```

## Step 3: Add `POST /verify-passcode` endpoint

Add before the existing `router.post('/start', ...)` handler:

```typescript
/** POST /api/tunnel/verify-passcode â€” Validate passcode and set session cookie. */
router.post('/verify-passcode', passcodeRateLimiter, async (req, res) => {
  const parsed = PasscodeVerifyRequestSchema.safeParse(req.body);
  if (!parsed.success) {
    return res.status(400).json({ ok: false, error: 'Invalid passcode format' });
  }

  const tunnelConfig = configManager.get('tunnel');
  if (!tunnelConfig?.passcodeHash || !tunnelConfig?.passcodeSalt) {
    return res.status(400).json({ ok: false, error: 'No passcode configured' });
  }

  const valid = await verifyPasscode(
    parsed.data.passcode,
    tunnelConfig.passcodeHash,
    tunnelConfig.passcodeSalt
  );

  if (!valid) {
    return res.status(401).json({ ok: false, error: 'Incorrect passcode' });
  }

  // Set session cookie
  req.session!.tunnelAuthenticated = true;
  return res.json({ ok: true });
});
```

## Step 4: Add `GET /session` endpoint

```typescript
/** GET /api/tunnel/session â€” Check current session authentication status. */
router.get('/session', (_req, res) => {
  const tunnelConfig = configManager.get('tunnel');
  const passcodeRequired = !!(tunnelConfig?.passcodeEnabled && tunnelConfig?.passcodeHash);
  const authenticated = !!_req.session?.tunnelAuthenticated;

  return res.json({ authenticated, passcodeRequired });
});
```

## Step 5: Add `POST /set-passcode` endpoint

```typescript
/** POST /api/tunnel/set-passcode â€” Set, update, or disable the tunnel passcode (localhost only). */
router.post('/set-passcode', async (req, res) => {
  // Only allow from localhost (passcode management is local-only)
  if (req.hostname !== 'localhost' && req.hostname !== '127.0.0.1') {
    return res.status(403).json({ error: 'Passcode can only be changed locally' });
  }

  const { passcode, enabled } = req.body;

  // Handle disable (clear passcode)
  if (enabled === false) {
    const tunnelConfig = configManager.get('tunnel');
    configManager.set('tunnel', {
      ...tunnelConfig,
      passcodeEnabled: false,
    });
    tunnelManager.refreshStatus();
    return res.json({ ok: true });
  }

  // Validate passcode format
  if (!passcode || !/^\d{6}$/.test(passcode)) {
    return res.status(400).json({ error: 'Passcode must be exactly 6 digits' });
  }

  const { hash, salt } = await hashPasscode(passcode);
  const tunnelConfig = configManager.get('tunnel');
  configManager.set('tunnel', {
    ...tunnelConfig,
