const handlePasscodeToggle = useCallback(
  async (checked: boolean) => {
    if (!checked) {
      // Disable passcode
      try {
        const res = await fetch('/api/tunnel/set-passcode', {
          method: 'POST',
          headers: { 'Content-Type': 'application/json' },
          body: JSON.stringify({ enabled: false }),
        });
        if (!res.ok) throw new Error('Failed to disable passcode');
        setPasscodeEnabled(false);
        setPasscodeInput('');
        queryClient.invalidateQueries({ queryKey: ['config'] });
      } catch {
        toast.error('Failed to disable passcode');
      }
    } else {
      setPasscodeEnabled(true);
    }
  },
  [queryClient]
);

const handleSavePasscode = useCallback(async () => {
  try {
    const res = await fetch('/api/tunnel/set-passcode', {
      method: 'POST',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify({ passcode: passcodeInput, enabled: true }),
    });
    if (!res.ok) throw new Error('Failed to save passcode');
    setPasscodeInput('');
    queryClient.invalidateQueries({ queryKey: ['config'] });
    toast.success('Passcode saved');
  } catch {
    toast.error('Failed to save passcode');
  }
}, [passcodeInput, queryClient]);
